// Auto-generated by scripts/gen-cli-reference.ts — do not edit by hand.
//
// CLI Reference Generator
// ========================
// This script reads the mogplex CLI command registry from the sibling
// mogplex-cli repo and generates MDX reference pages for the production-ready
// standalone subcommands, plus a single summary page for the additional names
// that still appear in `mogplex --help` but are not yet real standalone
// entrypoints.
//
// Registry location: ../mogplex-cli/packages/cli/src/subcommands.ts
//   - SUBCOMMAND_NAMES: array of canonical command names
//   - HIDDEN_SUBCOMMANDS: set of internal commands to exclude
//   - EXPERIMENTAL_SUBCOMMANDS: set of experimental commands (tagged)
//
// Summaries: ../mogplex-cli/packages/cli/src/help.ts
//   - SUMMARIES: Record<SubcommandName, string>
//
// Extraction approach: We import the modules directly via tsx at build time.
// This keeps the docs in sync with the actual CLI registry without needing
// to shell out to `mogplex --help` (which would require the CLI to be built).

import * as fs from "node:fs";
import * as path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const DOCS_ROOT = path.resolve(__dirname, "..");
const CLI_SRC = path.resolve(DOCS_ROOT, "..", "mogplex-cli", "packages", "cli", "src");
const OUTPUT_DIR = path.join(DOCS_ROOT, "content", "docs", "cli", "commands");

// ---------------------------------------------------------------------------
// Registry types (mirrored from CLI to avoid import issues)
// ---------------------------------------------------------------------------

type SubcommandName = string;

interface CommandRegistry {
  names: readonly SubcommandName[];
  hidden: ReadonlySet<SubcommandName>;
  experimental: ReadonlySet<SubcommandName>;
  implemented: ReadonlySet<SubcommandName>;
  summaries: Readonly<Record<string, string>>;
  aliases: Readonly<Record<string, SubcommandName>>;
}

// ---------------------------------------------------------------------------
// Parse the CLI source files to extract registry data
// ---------------------------------------------------------------------------

function extractQuotedSet(content: string, exportName: string): Set<string> {
  const pattern = new RegExp(
    `export const ${exportName}[^=]*=\\s*new Set\\(\\[([\\s\\S]*?)\\]\\)`
  );
  const match = content.match(pattern);
  const out = new Set<string>();
  if (!match?.[1]) return out;
  for (const m of match[1].matchAll(/"([^"]+)"/g)) {
    if (m[1]) out.add(m[1]);
  }
  return out;
}

function parseSubcommandsFile(content: string): {
  names: string[];
  hidden: Set<string>;
  experimental: Set<string>;
  implemented: Set<string>;
  aliases: Record<string, string>;
} {
  // Extract SUBCOMMAND_NAMES array
  const namesMatch = content.match(
    /export const SUBCOMMAND_NAMES\s*=\s*\[([\s\S]*?)\]\s*as const/
  );
  const names: string[] = [];
  if (namesMatch?.[1]) {
    const matches = namesMatch[1].matchAll(/"([^"]+)"/g);
    for (const m of matches) {
      if (m[1]) names.push(m[1]);
    }
  }

  const hidden = extractQuotedSet(content, "HIDDEN_SUBCOMMANDS");
  const experimental = extractQuotedSet(content, "EXPERIMENTAL_SUBCOMMANDS");
  const implemented = extractQuotedSet(content, "IMPLEMENTED_SUBCOMMANDS");

  // Extract SUBCOMMAND_ALIASES
  // Handles both quoted keys ("cloud-tasks") and unquoted keys (e, a)
  const aliasMatch = content.match(
    /export const SUBCOMMAND_ALIASES[^{]*\{([\s\S]*?)\}/
  );
  const aliases: Record<string, string> = {};
  if (aliasMatch?.[1]) {
    // Match quoted keys: "cloud-tasks": "cloud"
    const quotedMatches = aliasMatch[1].matchAll(/"([^"]+)"\s*:\s*"([^"]+)"/g);
    for (const m of quotedMatches) {
      if (m[1] && m[2]) aliases[m[1]] = m[2];
    }
    // Match unquoted keys: e: "exec"
    const unquotedMatches = aliasMatch[1].matchAll(/\b([a-z])\s*:\s*"([^"]+)"/g);
    for (const m of unquotedMatches) {
      if (m[1] && m[2]) aliases[m[1]] = m[2];
    }
  }

  return { names, hidden, experimental, implemented, aliases };
}

function parseHelpFile(content: string): Record<string, string> {
  // Extract SUMMARIES record
  const summariesMatch = content.match(
    /const SUMMARIES[^{]*\{([\s\S]*?)\};/
  );
  const summaries: Record<string, string> = {};
  if (summariesMatch?.[1]) {
    const matches = summariesMatch[1].matchAll(
      /["']?([a-z-]+)["']?\s*:\s*"([^"]+)"/g
    );
    for (const m of matches) {
      if (m[1] && m[2]) summaries[m[1]] = m[2];
    }
  }
  return summaries;
}

function loadRegistry(): CommandRegistry | null {
  // Only skip when the CLI source tree itself is absent (e.g. Vercel builds
  // that don't check out the sibling mogplex-cli repo). If the tree exists
  // but required files are missing, fail loudly — that's a real breakage.
  if (!fs.existsSync(CLI_SRC)) {
    return null;
  }

  const subcommandsPath = path.join(CLI_SRC, "subcommands.ts");
  const helpPath = path.join(CLI_SRC, "help.ts");

  if (!fs.existsSync(subcommandsPath)) {
    throw new Error(`CLI subcommands.ts not found at ${subcommandsPath}`);
  }
  if (!fs.existsSync(helpPath)) {
    throw new Error(`CLI help.ts not found at ${helpPath}`);
  }

  const subcommandsContent = fs.readFileSync(subcommandsPath, "utf-8");
  const helpContent = fs.readFileSync(helpPath, "utf-8");

  const { names, hidden, experimental, implemented, aliases } =
    parseSubcommandsFile(subcommandsContent);
  const summaries = parseHelpFile(helpContent);

  return { names, hidden, experimental, implemented, summaries, aliases };
}

