function getStatusText(cmd: CommandDoc): string {
  if (cmd.isImplemented && cmd.isExperimental) {
    return "Implemented experimental standalone command.";
  }
  if (cmd.isImplemented) {
    return "Implemented standalone command.";
  }
  if (cmd.isExperimental) {
    return "Help-surface-only experimental command name.";
  }
  return "Help-surface-only reserved command name.";
}

function getFallbackWorkarounds(cmd: CommandDoc): string[] {
  const specific = COMMAND_USE_TODAY[cmd.name];
  if (specific && specific.length > 0) {
    return specific;
  }
  return [
    "If you need this capability today, prefer a fully implemented path such as `mogplex exec`, `mogplex login`, `mogplex slash list`, or an in-session slash command.",
    "Treat this page as documentation for the name the binary advertises, not as a guarantee that the standalone path is production-ready yet.",
  ];
}

function getRelatedDocs(cmd: CommandDoc): RelatedDoc[] {
  return [
    ...(COMMAND_RELATED_DOCS[cmd.name] ?? []),
    { label: "All commands", href: "/cli/commands" },
  ];
}

function generateReservedNamesMdx(commands: CommandDoc[]): string {
  const reserved = commands.filter((cmd) => !cmd.isExperimental);
  const experimental = commands.filter((cmd) => cmd.isExperimental);
  const lines: string[] = [];

  lines.push("---");
  lines.push("title: Reserved Names");
  lines.push(
    "description: Names shown in `mogplex --help` that are not yet production-ready standalone commands."
  );
  lines.push("---");
  lines.push("");
  lines.push("{/* Auto-generated by scripts/gen-cli-reference.ts — do not edit by hand. */}");
  lines.push("");
  lines.push(
    "The CLI help surface currently includes some command names that are not yet fully wired as standalone entrypoints."
  );
  lines.push(
    "The docs keep these names visible because they are part of the published help surface, but they should not dominate the main command navigation."
  );
  lines.push("");
  lines.push("Use the implemented standalone commands for production workflows:");
  lines.push("");
  lines.push("- [`exec`](/cli/commands/exec)");
  lines.push("- [`login`](/cli/commands/login)");
  lines.push("- [`slash`](/cli/commands/slash)");
  lines.push("");
  lines.push("## Reserved names");
  lines.push("");

  if (reserved.length > 0) {
    for (const cmd of reserved) {
      lines.push(
        `- \`${cmd.name}\` — ${cmd.summary} ${getFallbackWorkarounds(cmd).join(" ")}`
      );
    }
  } else {
    lines.push("No reserved help-surface names are currently listed.");
  }

  lines.push("");
  lines.push("## Experimental names");
  lines.push("");

  if (experimental.length > 0) {
    for (const cmd of experimental) {
      lines.push(
        `- \`${cmd.name}\` — ${cmd.summary} ${getFallbackWorkarounds(cmd).join(" ")}`
      );
    }
  } else {
    lines.push("No experimental help-surface names are currently listed.");
  }

  lines.push("");
  lines.push("## Why this page exists");
  lines.push("");
  lines.push(
    "This page is the honest place to document the additional command names exposed by `mogplex --help` without pretending each one is already a production-ready standalone workflow."
  );
  lines.push("");
  lines.push("## See also");
  lines.push("");
  lines.push("- [Commands overview](/cli/commands)");
  lines.push("- [Exec Mode](/cli/guides/exec-mode)");
  lines.push("- [Slash Commands](/cli/guides/slash-commands)");
  lines.push("");

  return lines.join("\n");
}

function generateMdx(cmd: CommandDoc): string {
  const lines: string[] = [];

  // Front matter
  lines.push("---");
  lines.push(`title: ${cmd.name}`);
  lines.push(`description: ${cmd.summary}`);
  lines.push("---");
  lines.push("");
  lines.push("{/* Auto-generated by scripts/gen-cli-reference.ts — do not edit by hand. */}");
  lines.push("");

  // Experimental badge
  if (cmd.isExperimental) {
    lines.push("> **Experimental**: This command is experimental and may change.");
    lines.push("");
  }

  // Status
  lines.push("## Status");
  lines.push("");
  lines.push(getStatusText(cmd));
  lines.push("");

  // Synopsis
  lines.push("## Synopsis");
  lines.push("");
  lines.push("```bash");
  lines.push(`mogplex ${cmd.name} [OPTIONS] [ARGS]`);
  lines.push("```");
  lines.push("");

  // Description
  lines.push("## Description");
  lines.push("");
  lines.push(cmd.summary);
  lines.push("");

  // "Not yet implemented" notice is driven by the CLI's exported
  // IMPLEMENTED_SUBCOMMANDS set (packages/cli/src/subcommands.ts), so adding
  // a dispatcher in the CLI automatically updates the generated docs.
  if (!cmd.isImplemented) {
    lines.push("## Current Implementation Status");
    lines.push("");
    lines.push(
      `The command name is present in the CLI help surface, but the standalone \`mogplex ${cmd.name}\` path is not wired yet in the current build.`,
    );
    lines.push(
      `At the moment, running it can return \`Subcommand '${cmd.name}' is not yet implemented.\``,
    );
    lines.push("");

    lines.push("## What To Use Today");
    lines.push("");
    for (const item of getFallbackWorkarounds(cmd)) {
      lines.push(`- ${item}`);
    }
    lines.push("");

    lines.push("## Why This Page Exists");
    lines.push("");
    lines.push(
      "The docs intentionally track the names exposed by `mogplex --help`, even when a standalone command is still reserved or partial.",
    );
    lines.push(
      "That makes it clear which names are already part of the public help surface and which ones are not yet production-ready entrypoints.",
    );
    lines.push("");
  }

  // Aliases
  if (cmd.aliases.length > 0) {
    lines.push("## Aliases");
    lines.push("");
    for (const alias of cmd.aliases) {
      lines.push(`- \`${alias}\``);
    }
    lines.push("");
  }

  const extraSections = EXTRA_SECTIONS[cmd.name];
  if (extraSections) {
    lines.push(...extraSections);
    lines.push("");
  }

  // Run `mogplex <cmd> --help` hint — full option lists are owned by the CLI's own help output,
  // not duplicated here, so they never drift.
  lines.push("## Options");
  lines.push("");
  lines.push(`Run \`mogplex ${cmd.name} --help\` to see all supported flags.`);
  lines.push("");

  // See also
  lines.push("## See also");
  lines.push("");
  for (const related of getRelatedDocs(cmd)) {
    lines.push(`- [${related.label}](${related.href})`);
  }
  lines.push("");

  return lines.join("\n");
}

function generateMetaJson(
  implementedCommandNames: string[],
  includeReservedNames: boolean
): string {
  const pages = [
    "index",
    ...implementedCommandNames,
    ...(includeReservedNames ? ["reserved-names"] : []),
  ];
  const meta = {
    title: "Commands",
    defaultOpen: true,
    pages,
  };
  return JSON.stringify(meta, null, 2) + "\n";
}

// ---------------------------------------------------------------------------
// File writing helpers (idempotent - only writes if content changed)
// ---------------------------------------------------------------------------

function writeFileIfChanged(filePath: string, content: string): boolean {
  if (fs.existsSync(filePath)) {
    const existing = fs.readFileSync(filePath, "utf-8");
    if (existing === content) {
      return false;
    }
  }
  fs.writeFileSync(filePath, content);
  return true;
}

function removeFileIfExists(filePath: string): boolean {
  if (!fs.existsSync(filePath)) return false;
  fs.unlinkSync(filePath);
  return true;
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

function main(): void {
  console.log("Loading CLI command registry...");
  const registry = loadRegistry();

  if (!registry) {
    console.warn(
      `CLI source tree not found at ${CLI_SRC}. Skipping CLI reference generation; keeping existing generated files.`
    );
    return;
  }

  // Filter to visible commands only
  const visibleCommands = registry.names.filter(
    (name) => !registry.hidden.has(name)
  );
  const implementedCommands = visibleCommands.filter((name) =>
    registry.implemented.has(name)
  );
  const reservedCommands = visibleCommands.filter(
    (name) => !registry.implemented.has(name)
  );

  if (visibleCommands.length === 0) {
    console.error("No discoverable commands found in CLI registry.");
    console.log("Creating placeholder page...");

    const placeholderMdx = `---
title: Commands
description: CLI command reference (placeholder)
---

{/* Auto-generated by scripts/gen-cli-reference.ts — do not edit by hand. */}

No commands were discovered from the CLI registry. This may indicate the registry
structure has changed.
`;
    writeFileIfChanged(path.join(OUTPUT_DIR, "placeholder.mdx"), placeholderMdx);
    writeFileIfChanged(
      path.join(OUTPUT_DIR, "meta.json"),
      JSON.stringify({ title: "Commands", defaultOpen: true, pages: ["index", "placeholder"] }, null, 2) + "\n"
    );
    process.exit(0);
  }

  console.log(`Found ${visibleCommands.length} visible commands.`);

  // Build alias lookup (reverse: command -> aliases)
  const aliasesByCommand: Record<string, string[]> = {};
  for (const [alias, cmd] of Object.entries(registry.aliases)) {
    if (!aliasesByCommand[cmd]) aliasesByCommand[cmd] = [];
    aliasesByCommand[cmd].push(alias);
  }

  // Generate MDX for each implemented command
  const generatedNames: string[] = [];
  let changedCount = 0;
  for (const name of implementedCommands) {
    const cmd: CommandDoc = {
      name,
      summary: registry.summaries[name] ?? "No description available.",
      isExperimental: registry.experimental.has(name),
      isImplemented: registry.implemented.has(name),
      aliases: aliasesByCommand[name] ?? [],
    };

    const mdxContent = generateMdx(cmd);
    const outputPath = path.join(OUTPUT_DIR, `${name}.mdx`);
    const changed = writeFileIfChanged(outputPath, mdxContent);
    generatedNames.push(name);
    if (changed) {
      changedCount++;
      console.log(`  Generated: ${name}.mdx`);
    }
  }

  if (reservedCommands.length > 0) {
    const reservedDocs = reservedCommands.map((name) => ({
      name,
      summary: registry.summaries[name] ?? "No description available.",
      isExperimental: registry.experimental.has(name),
      isImplemented: false,
      aliases: aliasesByCommand[name] ?? [],
    }));
    const reservedContent = generateReservedNamesMdx(reservedDocs);
    const reservedPath = path.join(OUTPUT_DIR, "reserved-names.mdx");
    const changed = writeFileIfChanged(reservedPath, reservedContent);
    if (changed) {
      changedCount++;
      console.log("  Generated: reserved-names.mdx");
    }
  }

  const keepFiles = new Set<string>([
    "index.mdx",
    ...generatedNames.map((name) => `${name}.mdx`),
    ...(reservedCommands.length > 0 ? ["reserved-names.mdx"] : []),
  ]);

  for (const entry of fs.readdirSync(OUTPUT_DIR)) {
    if (!entry.endsWith(".mdx")) continue;
    if (keepFiles.has(entry)) continue;
    const removed = removeFileIfExists(path.join(OUTPUT_DIR, entry));
    if (removed) {
      changedCount++;
      console.log(`  Removed: ${entry}`);
    }
  }

  // Generate meta.json
  const metaContent = generateMetaJson(
    generatedNames,
    reservedCommands.length > 0
  );
  const metaChanged = writeFileIfChanged(path.join(OUTPUT_DIR, "meta.json"), metaContent);
  if (metaChanged) {
    changedCount++;
    console.log(
      `  Generated: meta.json with ${generatedNames.length + 1 + (reservedCommands.length > 0 ? 1 : 0)} pages`
    );
  }

  if (changedCount === 0) {
    console.log(`Done. All ${generatedNames.length} command pages are up to date.`);
  } else {
    console.log(`Done. Updated ${changedCount} file(s).`);
  }
}

main();
